149				expectNeeds: []string{string(constants.AgentJobName), string(constants.ActivationJobName), "add_comment", "create_issue", "my_custom_job", "another_custom_safe_job"},
150			},
151		}
152	
153		for _, tt := range tests {
154			t.Run(tt.name, func(t *testing.T) {
155				// Create a test workflow
156				compiler := NewCompiler()
157				workflowData := &WorkflowData{
158					Name:       "Test Workflow",
159					AIReaction: tt.aiReaction,
160					Command:    tt.command,
161				}
162	
163				if tt.addCommentConfig {
164					workflowData.SafeOutputs = &SafeOutputsConfig{
165						AddComments: &AddCommentsConfig{
166							BaseSafeOutputConfig: BaseSafeOutputConfig{
167								Max: strPtr("1"),
168							},
169						},
170					}
171				} else if len(tt.safeOutputJobNames) > 0 {
172					// If there are safe output jobs but no add-comment, create a minimal SafeOutputs config
173					// This represents a scenario where other safe outputs exist (like missing_tool)
174					workflowData.SafeOutputs = &SafeOutputsConfig{
175						MissingTool: &MissingToolConfig{},
176					}
177				}
178	
179				// Build the conclusion job
180				job, err := compiler.buildConclusionJob(workflowData, string(constants.AgentJobName), tt.safeOutputJobNames)
181				if err != nil {
182					t.Fatalf("Failed to build conclusion job: %v", err)
183				}
184	
185				if tt.expectJob {
186					if job == nil {
187						t.Fatal("Expected conclusion job to be created, but got nil")
188					}
189	
190					// Check job name
191					if job.Name != "conclusion" {
192						t.Errorf("Expected job name 'conclusion', got '%s'", job.Name)
193					}
194	
195					// Check conditions
196					for _, expectedCond := range tt.expectConditions {
197						if !strings.Contains(job.If, expectedCond) {
198							t.Errorf("Expected condition '%s' to be in job.If, but it wasn't.\nActual If: %s", expectedCond, job.If)
199						}
200					}
201	
202					// Check needs
203					if len(job.Needs) != len(tt.expectNeeds) {
204						t.Errorf("Expected %d needs, got %d: %v", len(tt.expectNeeds), len(job.Needs), job.Needs)
205					}
206					for _, expectedNeed := range tt.expectNeeds {
207						found := slices.Contains(job.Needs, expectedNeed)
208						if !found {
209							t.Errorf("Expected need '%s' not found in job.Needs: %v", expectedNeed, job.Needs)
210						}
211					}
212	
213					// Check permissions based on what safe-outputs are configured
214					// When add-comment is configured, it requires issues and discussions permissions
215					// (PR comments are issue comments, so only issues: write is needed, not pull-requests: write)
216					// When only missing_tool/noop is configured, minimal permissions are needed
217					if tt.addCommentConfig {
218						// add-comment requires issues and discussions write permissions
219						if !strings.Contains(job.Permissions, "issues: write") {
220							t.Error("Expected 'issues: write' permission when add-comment is configured")
221						}
222						if !strings.Contains(job.Permissions, "discussions: write") {
223							t.Error("Expected 'discussions: write' permission when add-comment is configured")
224						}
225					}
226					// No need to check for specific permissions when only noop/missing_tool is configured
227					// as they don't require write permissions on their own
228	
229					// Check that the job has the update reaction step (if expected)
230					stepsYAML := strings.Join(job.Steps, "")
231					hasUpdateStep := strings.Contains(stepsYAML, "Update reaction comment with completion status")
232					if tt.expectUpdateStep {
233						if !hasUpdateStep {
234							t.Errorf("[%s] Expected 'Update reaction comment with completion status' step in conclusion job", tt.name)
235						}
236						if !strings.Contains(stepsYAML, "GH_AW_COMMENT_ID") {
237							t.Errorf("[%s] Expected GH_AW_COMMENT_ID environment variable in conclusion job", tt.name)
238						}
239					} else {
240						if hasUpdateStep {
241							t.Errorf("[%s] Did not expect 'Update reaction comment with completion status' step in conclusion job", tt.name)
242						}
243					}
244					// GH_AW_AGENT_CONCLUSION should always be present for agent failure handling
245					if !strings.Contains(stepsYAML, "GH_AW_AGENT_CONCLUSION") {
246						t.Errorf("[%s] Expected GH_AW_AGENT_CONCLUSION environment variable in conclusion job", tt.name)
247					}
248				} else {
249					if job != nil {
250						t.Errorf("Expected no conclusion job, but got one: %v", job)
251					}
252				}
253			})
254		}
255	}
