            "skip-if-match": {
              "oneOf": [
                {
                  "type": "string",
                  "description": "GitHub search query string to check before running workflow (implies max=1). If the search returns any results, the workflow will be skipped. Query is automatically scoped to the current repository. Example: 'is:issue is:open label:bug'"
                },
                {
                  "type": "object",
                  "required": ["query"],
                  "properties": {
                    "query": {
                      "type": "string",
                      "description": "GitHub search query string to check before running workflow. Query is automatically scoped to the current repository."
                    },
                    "max": {
                      "description": "Maximum number of items that must be matched for the workflow to be skipped. Defaults to 1 if not specified. Supports integer or GitHub Actions expression (e.g. '${{ inputs.max }}').",
                      "oneOf": [
                        {
                          "type": "integer",
                          "minimum": 1
                        },
                        {
                          "type": "string",
                          "pattern": "^\\$\\{\\{.*\\}\\}$",
                          "description": "GitHub Actions expression that resolves to an integer at runtime"
                        }
                      ]
                    },
                    "scope": {
                      "type": "string",
                      "enum": ["none"],
                      "description": "Scope for the search query. Set to 'none' to disable the automatic 'repo:owner/repo' scoping, enabling org-wide or cross-repo queries."
                    }
                  },
                  "additionalProperties": false,
                  "description": "Skip-if-match configuration object with query, maximum match count, and optional scope. For custom authentication use the top-level on.github-token or on.github-app fields."
                }
              ],
              "description": "Conditionally skip workflow execution when a GitHub search query has matches. Can be a string (query only, implies max=1) or an object with 'query', optional 'max', and 'scope' fields. Use top-level on.github-token or on.github-app for custom authentication."
            },
            "skip-if-no-match": {
              "oneOf": [
                {
                  "type": "string",
