                  "close-older-issues": true
                }
              ]
            },
            {
              "type": "null",
              "description": "Enable issue creation with default configuration"
            }
          ],
          "description": "Enable AI agents to create GitHub issues from workflow output. Supports title prefixes, automatic labeling, assignees, and cross-repository creation. Does not require 'issues: write' permission."
