    "import-schema": {
      "type": "object",
      "description": "Schema for validating 'with' input values when this workflow is imported by another workflow using the 'uses'/'with' syntax. Defines the expected parameters, their types, and whether they are required. Scalar inputs are accessible via '${{ github.aw.import-inputs.<name> }}' expressions. Object inputs (type: object) allow one-level deep sub-fields accessible via '${{ github.aw.import-inputs.<name>.<subkey> }}' expressions.",
      "additionalProperties": {
        "oneOf": [
          {
            "type": "object",
            "description": "Input parameter definition for scalar types (string, number, boolean, choice).",
            "properties": {
              "description": {
                "type": "string",
                "description": "Human-readable description of the input parameter."
              },
              "required": {
                "type": "boolean",
                "description": "Whether this input is required when using 'with' in an import.",
                "default": false
              },
              "default": {
                "description": "Default value used when 'with' does not provide this input."
              },
              "type": {
                "type": "string",
                "enum": ["string", "number", "boolean", "choice", "array"],
                "description": "The type of the input value."
              },
              "options": {
                "type": "array",
                "description": "List of allowed values for choice type inputs.",
                "items": {
                  "type": "string"
                }
              },
              "items": {
                "type": "object",
                "description": "Schema for individual array elements. Typically {\"type\": \"string\"}.",
                "properties": {
                  "type": {
                    "type": "string",
                    "enum": ["string", "number", "boolean"],
                    "description": "Type of each array item."
                  }
                },
                "additionalProperties": false
              }
            },
            "additionalProperties": false
          },
          {
            "type": "object",
            "description": "Input parameter definition for object type (one level deep). Use 'properties' to declare the expected sub-fields.",
            "required": ["type"],
            "properties": {
              "description": {
                "type": "string",
                "description": "Human-readable description of the input parameter."
              },
              "required": {
                "type": "boolean",
                "description": "Whether this input is required when using 'with' in an import.",
                "default": false
              },
              "type": {
                "type": "string",
                "enum": ["object"],
                "description": "The type 'object' enables structured sub-fields accessible via 'github.aw.import-inputs.<name>.<subkey>'."
              },
              "properties": {
                "type": "object",
                "description": "One-level deep property definitions for this object input.",
                "additionalProperties": {
                  "type": "object",
                  "description": "Sub-property definition.",
                  "properties": {
                    "description": {
                      "type": "string"
                    },
                    "required": {
                      "type": "boolean",
                      "default": false
                    },
                    "default": {},
                    "type": {
                      "type": "string",
                      "enum": ["string", "number", "boolean", "choice"],
                      "description": "Type of the sub-property."
                    },
                    "options": {
                      "type": "array",
                      "items": {
                        "type": "string"
                      }
                    }
                  },
                  "additionalProperties": false
                }
              }
            },
            "additionalProperties": false
          }
        ]
      },
      "examples": [
        {
          "count": {
            "type": "number",
            "description": "Number of items to process",
            "required": true
          },
          "category": {
            "type": "string",
            "description": "Category filter",
            "default": "general"
          },
